SELECT a.*, s.student_number, u.real_name as student_name, s.class_name, r.room_number, b.name as building_name, u2.real_name as checker_name FROM attendance a LEFT JOIN student s ON a.student_id = s.id LEFT JOIN user u ON s.user_id = u.id LEFT JOIN assignment asgn ON s.id = asgn.student_id AND asgn.status = 'ACTIVE' LEFT JOIN room r ON asgn.room_id = r.id LEFT JOIN building b ON r.building_id = b.id LEFT JOIN user u2 ON a.checker_id = u2.id
AND a.student_id = #{studentId}
AND r.building_id = #{buildingId}
AND a.check_date = #{checkDate}
AND a.check_time = #{checkTime}
AND a.status = #{status}
ORDER BY a.check_date DESC, a.check_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM attendance a
LEFT JOIN student s ON a.student_id = s.id
LEFT JOIN assignment asgn ON s.id = asgn.student_id AND asgn.status = 'ACTIVE'
LEFT JOIN room r ON asgn.room_id = r.id


        AND a.student_id = #{studentId}


        AND r.building_id = #{buildingId}


        AND a.check_date = #{checkDate}


        AND a.check_time = #{checkTime}


        AND a.status = #{status}

SELECT * FROM attendance 
WHERE student_id = #{studentId} 
AND check_date = #{checkDate}
AND check_time = #{checkTime}

